import{_ as t,o,c as a,i as n}from"./chunks/framework.B0tbiLr2.js";const u=JSON.parse('{"title":"Getting Started for Product Managers","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/product-managers.md","filePath":"getting-started/product-managers.md"}'),r={name:"getting-started/product-managers.md"};function s(i,e,d,l,c,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="getting-started-for-product-managers" tabindex="-1">Getting Started for Product Managers <a class="header-anchor" href="#getting-started-for-product-managers" aria-label="Permalink to &quot;Getting Started for Product Managers&quot;">​</a></h1><p>This guide explains what the Cobalt Design System provides, how it fits into your product workflow, and how to request changes or new components.</p><h2 id="what-cobalt-provides" tabindex="-1">What Cobalt Provides <a class="header-anchor" href="#what-cobalt-provides" aria-label="Permalink to &quot;What Cobalt Provides&quot;">​</a></h2><p>Cobalt is a shared library of reusable UI components, design tokens, and guidelines that product teams use to build consistent interfaces. As a product manager, the design system affects your work in three key areas:</p><ul><li><strong>Faster delivery</strong> — teams spend less time designing and building common UI patterns from scratch.</li><li><strong>Consistent experience</strong> — users see the same interactions and visual language across every product surface.</li><li><strong>Built-in accessibility</strong> — every component meets WCAG 2.1 AA standards, reducing compliance risk.</li><li><strong>Cross-tool integration</strong> — a shared language and toolkit enables streamlined integration between various tools.</li></ul><h2 id="how-it-fits-your-workflow" tabindex="-1">How It Fits Your Workflow <a class="header-anchor" href="#how-it-fits-your-workflow" aria-label="Permalink to &quot;How It Fits Your Workflow&quot;">​</a></h2><h3 id="during-discovery" tabindex="-1">During Discovery <a class="header-anchor" href="#during-discovery" aria-label="Permalink to &quot;During Discovery&quot;">​</a></h3><p>When scoping a feature, check the Cobalt component library first. Many common patterns are already solved and the component list is growing.</p><p>Using existing components means less design and development effort, which translates to smaller estimates and faster development times.</p><h3 id="during-design-review" tabindex="-1">During Design Review <a class="header-anchor" href="#during-design-review" aria-label="Permalink to &quot;During Design Review&quot;">​</a></h3><p>Look for these signals that the design is aligned with Cobalt:</p><ol><li>Components match their Cobalt counterparts in Figma.</li><li>Colors, spacing, and typography use named tokens — not arbitrary values.</li><li>Interactive states (hover, focus, disabled, error) are accounted for.</li><li>The design includes responsive considerations for mobile, tablet, and desktop.</li></ol><blockquote><p><strong>Tip:</strong> If a design introduces a pattern that looks custom, ask whether an existing Cobalt component could cover the use case. Custom components add maintenance cost and slow down future redesigns.</p></blockquote><h3 id="during-development" tabindex="-1">During Development <a class="header-anchor" href="#during-development" aria-label="Permalink to &quot;During Development&quot;">​</a></h3><p>Cobalt components are production-ready. When a developer picks up a story, they import the component and configure it with props — they do not rebuild it. This means:</p><ul><li>Fewer bugs related to UI behavior.</li><li>Shorter code review cycles for UI-heavy features.</li><li>Consistent behavior across teams without extra coordination.</li></ul><h2 id="requesting-new-components" tabindex="-1">Requesting New Components <a class="header-anchor" href="#requesting-new-components" aria-label="Permalink to &quot;Requesting New Components&quot;">​</a></h2><p>Not every pattern exists in Cobalt yet. When you identify a gap, here is how to get a new component or enhancement added.</p><h3 id="check-existing-components-first" tabindex="-1">Check Existing Components First <a class="header-anchor" href="#check-existing-components-first" aria-label="Permalink to &quot;Check Existing Components First&quot;">​</a></h3><p>Search the <a href="/cobalt-design-system/components/button.html">component documentation</a> to confirm the pattern is not already covered. Sometimes an existing component with different props can solve the use case.</p><h3 id="submit-a-proposal" tabindex="-1">Submit a Proposal <a class="header-anchor" href="#submit-a-proposal" aria-label="Permalink to &quot;Submit a Proposal&quot;">​</a></h3><p>If no existing component fits, submit a proposal through the <a href="/cobalt-design-system/contributing/component-proposal.html">Component Proposal Process</a>. The proposal template asks for use case, scope, and examples — include priority and cross-team demand to help with prioritization.</p><p>When reviewing proposals, the team weighs these criteria:</p><table tabindex="0"><thead><tr><th>Criteria</th><th>Weight</th><th>Description</th></tr></thead><tbody><tr><td>Cross-team demand</td><td>High</td><td>Is this needed by more than one product team?</td></tr><tr><td>User impact</td><td>High</td><td>Does this affect a core workflow or conversion path?</td></tr><tr><td>Complexity</td><td>Medium</td><td>How much design and development effort is required?</td></tr><tr><td>Workaround availability</td><td>Medium</td><td>Can teams use an existing component as a stopgap?</td></tr><tr><td>Strategic alignment</td><td>Low</td><td>Does this support a broader platform initiative?</td></tr></tbody></table><h2 id="governance-and-contributions" tabindex="-1">Governance and Contributions <a class="header-anchor" href="#governance-and-contributions" aria-label="Permalink to &quot;Governance and Contributions&quot;">​</a></h2><p>Cobalt is maintained by a dedicated design system team, but it is governed collaboratively with product teams. Product teams can also contribute components directly. For details on governance roles and the contribution process, see the <a href="/cobalt-design-system/contributing/">Contributing</a> guide.</p><h2 id="measuring-impact" tabindex="-1">Measuring Impact <a class="header-anchor" href="#measuring-impact" aria-label="Permalink to &quot;Measuring Impact&quot;">​</a></h2><p>Track the value of the design system with these metrics:</p><ul><li><strong>Adoption rate</strong> — percentage of product surfaces using Cobalt components.</li><li><strong>Time-to-ship</strong> — compare feature delivery timelines before and after adoption.</li><li><strong>Bug density</strong> — UI-related bug count in Cobalt components vs. custom implementations.</li><li><strong>Consistency score</strong> — periodic audits measuring visual and interaction consistency across products.</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Component Library:</strong> <a href="/cobalt-design-system/components/button.html">Browse Components</a></li><li><strong>Roadmap:</strong> <code>cobalt-design-system</code> GitHub project board</li><li><strong>Support:</strong> See the <a href="/cobalt-design-system/resources/contact.html">Contact</a> page for all support channels</li></ul>',31)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
